// Este nodo orquesta múltiples queries a Supabase vía fetch
// para calcular todos los KPIs del gym en una sola pasada.
const gym = $input.first().json;
const gymId = gym.id;

const SUPABASE_URL = $env['SUPABASE_URL'];
const SERVICE_KEY  = $env['SUPABASE_SERVICE_ROLE_KEY'];
const headers = {
  'Authorization': `Bearer ${SERVICE_KEY}`,
  'apikey': SERVICE_KEY,
  'Content-Type': 'application/json',
  'Prefer': 'return=representation'
};

const today = new Date().toISOString().split('T')[0];
const monthStart = new Date(new Date().getFullYear(), new Date().getMonth(), 1).toISOString();
const churnCutoff = new Date(Date.now() - 14*24*60*60*1000).toISOString();

async function q(path) {
  const res = await fetch(`${SUPABASE_URL}/rest/v1/${path}`, { headers });
  return res.json();
}

const [memberships, todayOrders, allLeads, todayBookings, rooms, recentAccess] = await Promise.all([
  q(`memberships?gym_id=eq.${gymId}&select=status,price_per_cycle`),
  q(`orders?gym_id=eq.${gymId}&status=eq.paid&created_at=gte.${today}&select=amount`),
  q(`leads?gym_id=eq.${gymId}&select=stage,created_at`),
  q(`bookings?gym_id=eq.${gymId}&status=eq.booked&select=id,class_id`),
  q(`class_slots?gym_id=eq.${gymId}&select=capacity`),
  q(`access_logs?gym_id=eq.${gymId}&status=eq.allowed&scanned_at=gte.${churnCutoff}&select=user_id`)
]);

const active = memberships.filter(m => m.status === 'active');
const frozen = memberships.filter(m => m.status === 'frozen');
const expired = memberships.filter(m => m.status === 'expired');
const mrr = active.reduce((s, m) => s + (m.price_per_cycle || 0), 0);
const todayRevenue = (todayOrders || []).reduce((s, o) => s + (o.amount || 0), 0);

const totalLeads = allLeads.length;
const converted  = allLeads.filter(l => l.stage === 'converted').length;
const newLeads   = allLeads.filter(l => l.stage === 'new').length;
const crmRate    = totalLeads > 0 ? Math.round((converted / totalLeads) * 100) : 0;

const maxCapacity = (rooms || []).reduce((s, r) => s + (r.capacity || 0), 0);
const currentOcc  = (todayBookings || []).length;

// Churn: members NOT seen in access_logs in last 14 days
const recentUserIds = new Set((recentAccess || []).map(a => a.user_id));
const churnRisk = active.filter(m => m.user_id && !recentUserIds.has(m.user_id)).length;

return [{ json: {
  gym_id: gymId,
  gym_name: gym.name,
  mrr,
  today_revenue: todayRevenue,
  active_members: active.length,
  frozen_members: frozen.length,
  expired_members: expired.length,
  current_occupancy: currentOcc,
  max_capacity: maxCapacity,
  crm_total_leads: totalLeads,
  crm_new_leads: newLeads,
  crm_conversion_rate: crmRate,
  churn_risk_count: churnRisk,
  computed_at: new Date().toISOString()
} }];
